			want:      true,
		},
		{
			name:      "different equality does not overlap",
			selector1: mustParseSelector(t, "env=prod"),
			selector2: mustParseSelector(t, "env=dev"),
			want:      false,
		},
		{
			name:      "subset match labels overlap",
			selector1: mustParseSelector(t, "env=prod"),
			selector2: mustParseSelector(t, "env=prod,tier=frontend"),
			want:      true,
